// Dotted World Map (Pure SVG)
const DottedWorldMap = ({
  activeIndex,
  onSelect,
  hoveredIndex,
  onHover,
}: {
  activeIndex: number | null;
  onSelect: (index: number | null) => void;
  hoveredIndex: number | null;
  onHover: (index: number | null) => void;
}) => {
  const maxUsers = Math.max(...geographyCountries.map((c) => c.users));
  const minRadius = 1.2;
  const maxRadius = 2.8;

  return (
    <svg
      viewBox="0 0 63 30"
      preserveAspectRatio="xMidYMid meet"
      className="h-full w-full"
      onMouseLeave={() => onHover(null)}
    >
      <defs>
        <style>{`
          @keyframes mapMarkerPulse {
            0% { opacity: 1.0; }
            50% { opacity: 0.65; }
            100% { opacity: 1.0; }
          }
        `}</style>
      </defs>
      {mapBasePoints.map((point, i) => {
        let dotOpacity = 0.12;
        if (hoveredIndex !== null) {
          const boosted = spotlightMaps[hoveredIndex].get(i);
          dotOpacity = boosted !== undefined ? boosted : 0.12;
        }
        return (
          <circle
            key={i}
            cx={point.x}
            cy={point.y}
            r={0.35}
            fill="currentColor"
            opacity={dotOpacity}
            style={{ transition: "opacity 300ms ease-out" }}
          />
        );
      })}

      {geographyPinPositions.map((pin, i) => {
        const isActive = activeIndex === i;
        const isHovered = hoveredIndex === i;
        const isDimmed =
          (activeIndex !== null || hoveredIndex !== null) &&
          !isActive &&
          !isHovered;
        const ratio = geographyCountries[i].users / maxUsers;
        const baseR = minRadius + ratio * (maxRadius - minRadius);
        const r = isActive ? baseR * 1.15 : isHovered ? baseR * 1.08 : baseR;

        const markerFill = isActive
          ? palette.primary
          : isHovered
            ? palette.secondary.light
            : palette.tertiary.light;
        const markerOpacity = isActive
          ? 0.7
          : isHovered
            ? 0.6
            : isDimmed
              ? 0.2
              : 0.5;
        const isIdle = !isActive && !isHovered && !isDimmed;

        return (
          <g
            key={geographyCountries[i].name}
            onClick={() => onSelect(isActive ? null : i)}
            onMouseEnter={() => onHover(i)}
            onMouseLeave={() => onHover(null)}
            onFocus={() => onHover(i)}
            onBlur={() => onHover(null)}
            onKeyDown={(event) => {
              if (!isActivationKey(event)) return;
              event.preventDefault();
              onSelect(isActive ? null : i);
            }}
            tabIndex={0}
            role="button"
            aria-pressed={isActive}
            aria-label={`${geographyCountries[i].name}: ${numberFormatter.format(geographyCountries[i].users)} users`}
            style={{
              cursor: "pointer",
              animation: isIdle
                ? `mapMarkerPulse 3s ease-in-out ${i * 0.6}s infinite`
                : "none",
            }}
          >
            {isActive && (
              <circle
                cx={pin.x}
                cy={pin.y}
                r={r * 2.5}
                fill={palette.primary}
                fillOpacity={0.08}
                stroke={palette.primary}
                strokeWidth={0.3}
                strokeOpacity={0.15}
                style={{ transition: "all 150ms ease-out" }}
              />
            )}
            {isHovered && !isActive && (
              <circle
                cx={pin.x}
                cy={pin.y}
                r={r * 2.0}
                fill={palette.tertiary.light}
                fillOpacity={0.06}
                stroke={palette.tertiary.light}
                strokeWidth={0.2}
                strokeOpacity={0.12}
                style={{ transition: "all 150ms ease-out" }}
              />
            )}
            <circle
              cx={pin.x}
              cy={pin.y}
              r={r}
              fill={markerFill}
              fillOpacity={markerOpacity}
              stroke={markerFill}
              strokeWidth={0.4}
              strokeOpacity={
                isActive ? 0.9 : isHovered ? 0.6 : isDimmed ? 0.1 : 0.4
              }
              style={{ transition: "all 150ms ease-out" }}
            />
          </g>
        );
      })}
    </svg>
  );
};

// Geography Card
const GeographyCard = () => {
  const [activeIndex, setActiveIndex] = React.useState<number | null>(null);
  const [hoveredIndex, setHoveredIndex] = React.useState<number | null>(null);

  const selected =
    activeIndex !== null ? geographyCountries[activeIndex] : null;
  const hovered =
    hoveredIndex !== null ? geographyCountries[hoveredIndex] : null;
  const previewCountry = hovered ?? selected;

  const globalDemographics = {
    men: Math.round(
      geographyCountries.reduce((s, c) => s + c.demographics.men * c.users, 0) /
        totalGeographyUsers,
    ),
    women: Math.round(
      geographyCountries.reduce(
        (s, c) => s + c.demographics.women * c.users,
        0,
      ) / totalGeographyUsers,
    ),
    other: Math.round(
      geographyCountries.reduce(
        (s, c) => s + c.demographics.other * c.users,
        0,
      ) / totalGeographyUsers,
    ),
  };

  const displayUsers = previewCountry
    ? previewCountry.users
    : totalGeographyUsers;
  const displayDemographics = previewCountry
    ? previewCountry.demographics
    : globalDemographics;
  const displayLabel = previewCountry
    ? { flag: previewCountry.flag, name: previewCountry.name }
    : null;

  const tooltipCountry = hovered;
  const tooltipPin =
    hoveredIndex !== null ? geographyPinPositions[hoveredIndex] : null;

  const viewBoxW = 63;
  const viewBoxH = 30;

  let tooltipLeft = 0;
  let tooltipTop = 0;
  let tooltipAbove = false;
  if (tooltipPin) {
    tooltipLeft = (tooltipPin.x / viewBoxW) * 100;
    tooltipTop = (tooltipPin.y / viewBoxH) * 100;
    tooltipAbove = tooltipPin.y > viewBoxH / 2;
  }

  const tooltipTranslateX =
    tooltipLeft < 20 ? "0%" : tooltipLeft > 80 ? "-100%" : "-50%";

  return (
    <div className="bg-card flex min-w-0 flex-col gap-4 p-4 sm:gap-5 sm:p-5">
      <div className="flex items-start justify-between gap-4">
        <div className="flex flex-col gap-1">
          <span className="text-muted-foreground text-xs">Geography</span>
          <div className="flex items-baseline gap-2">
            <span
              className={cn(
                jetBrainsMono.className,
                "text-2xl font-semibold tabular-nums",
              )}
            >
              {numberFormatter.format(displayUsers)}
            </span>
            {displayLabel && (
              <span className="bg-muted/30 text-muted-foreground flex items-center gap-1 border px-1.5 py-0.5 text-xs">
                {displayLabel.flag} {displayLabel.name}
              </span>
            )}
          </div>
        </div>
        <Button variant="outline" size="sm" className="h-7 px-2 text-xs">
          Details
        </Button>
      </div>

      <div className="flex items-center gap-3">
        <div className="flex h-1.5 flex-1 overflow-hidden">
          <div
            style={{
              width: `${displayDemographics.men}%`,
              backgroundColor: palette.primary,
              transition: "width 150ms ease-out",
            }}
            className="h-full"
          />
          <div
            style={{
              width: `${displayDemographics.women}%`,
              backgroundColor: palette.tertiary.light,
              transition: "width 150ms ease-out",
            }}
            className="h-full"
          />
          <div
            style={{
              width: `${displayDemographics.other}%`,
              backgroundColor: palette.quinary.light,
              transition: "width 150ms ease-out",
            }}
            className="h-full"
          />
        </div>
      </div>
      <div className="text-muted-foreground flex items-center gap-3 text-xs">
        <span className="flex items-center gap-1">
          <span
            className="inline-block h-1.5 w-1.5 rounded-full"
            style={{ backgroundColor: palette.primary }}
          />
          Men {displayDemographics.men}%
        </span>
        <span className="flex items-center gap-1">
          <span
            className="inline-block h-1.5 w-1.5 rounded-full"
            style={{ backgroundColor: palette.tertiary.light }}
          />
          Women {displayDemographics.women}%
        </span>
        <span className="flex items-center gap-1">
          <span
            className="inline-block h-1.5 w-1.5 rounded-full"
            style={{ backgroundColor: palette.quinary.light }}
          />
          Other {displayDemographics.other}%
        </span>
      </div>

      <div className="relative h-[200px]">
        <DottedWorldMap
          activeIndex={activeIndex}
          onSelect={setActiveIndex}
          hoveredIndex={hoveredIndex}
          onHover={setHoveredIndex}
        />

        {tooltipCountry && tooltipPin && (
          <div
            className="border-border bg-popover pointer-events-none absolute z-10 flex flex-col gap-1.5 border px-3 py-2 shadow-lg"
            style={{
              left: `${tooltipLeft}%`,
              top: tooltipAbove ? `${tooltipTop}%` : `${tooltipTop}%`,
              transform: `${tooltipTranslateX !== "-50%" ? `translateX(${tooltipTranslateX})` : "translateX(-50%)"} ${tooltipAbove ? "translateY(calc(-100% - 12px))" : "translateY(12px)"}`,
              opacity: 1,
              transition: "opacity 150ms ease-out, transform 150ms ease-out",
            }}
          >
            <div className="text-foreground flex items-center gap-1.5 text-xs font-medium">
              <span>{tooltipCountry.flag}</span>
              <span>{tooltipCountry.name}</span>
            </div>
            <span
              className={cn(
                jetBrainsMono.className,
                "text-foreground text-sm font-semibold tabular-nums",
              )}
            >
              {numberFormatter.format(tooltipCountry.users)}
            </span>
            <div className="flex h-1 w-full overflow-hidden">
              <div
                style={{
                  width: `${tooltipCountry.demographics.men}%`,
                  backgroundColor: palette.primary,
                }}
                className="h-full"
              />
              <div
                style={{
                  width: `${tooltipCountry.demographics.women}%`,
                  backgroundColor: palette.tertiary.light,
                }}
                className="h-full"
              />
              <div
                style={{
                  width: `${tooltipCountry.demographics.other}%`,
                  backgroundColor: palette.quinary.light,
                }}
                className="h-full"
              />
            </div>
            <div className="text-muted-foreground flex items-center gap-2 text-[10px]">
              <span>M {tooltipCountry.demographics.men}%</span>
              <span>W {tooltipCountry.demographics.women}%</span>
              <span>O {tooltipCountry.demographics.other}%</span>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

